UPDATE campaign 
SET applicants_num = (
    SELECT t.cnt FROM (
        SELECT COUNT(DISTINCT user_id) as cnt
        FROM user_campaign 
        WHERE campaign_id = #{campaignId}
        AND is_deleted = 'N'
        -- 'N'인 인솔자만 제외하고, 일반 사용자(NULL)와 Y인 인솔자는 모두 포함합니다.
        AND (lead_apply IS NULL OR lead_apply != 'N')
    ) t
)
WHERE campaign_id = #{campaignId}

UPDATE campaign set
    is_active ='N'
WHERE campaign_id = #{id}

mapper.select:

SELECT COUNT(*)
FROM user_campaign uc
WHERE uc.user_no = #{userNo}
AND uc.is_deleted = 'N'
AND (
    uc.event_str_date <= #{eventPeriodEnd} 
    AND uc.event_end_date >= #{eventPeriodStr}
)
AND uc.time_segment = #{timeSegment}


SELECT 
    c.campaign_title
FROM user_campaign uc
LEFT OUTER JOIN campaign c ON uc.campaign_id = c.campaign_id
WHERE uc.user_no = #{userNo}
AND uc.is_deleted = 'N'
-- 1. 날짜 기간이 겹치는지 확인
AND (
    uc.event_str_date <= #{eventPeriodEnd}
    AND uc.event_end_date >= #{eventPeriodStr}
)
-- 2. 🔥 [추가] 시간대(주야간)까지 겹치는지 확인
AND c.time_segment = #{timeSegment}
LIMIT 1
